const climate = $input.all()[0]?.json || {};
const current = $input.all()[1]?.json || {};

// 30-day precipitation total
const precipSums = climate.daily?.precipitation_sum || [];
const total30d = precipSums.reduce((s, v) => s + (v || 0), 0);

// Evapotranspiration (water demand)
const et0Sums = climate.daily?.et0_fao_evapotranspiration || [];
const totalET0 = et0Sums.reduce((s, v) => s + (v || 0), 0);

// Soil moisture (first available hourly reading)
const soilMoisture = (climate.hourly?.soil_moisture_0_to_1cm || [])[0] || 0.2;

// Current temperature and humidity
const temp = current.current?.temperature_2m || 15;
const humidity = current.current?.relative_humidity_2m || 60;

// Drought index: Water deficit = ET0 - Precipitation (Palmer-inspired)
const waterDeficit = totalET0 - total30d;
const soilDryness = Math.max(0, 1 - (soilMoisture / 0.35)); // normalize: 0.35 = field capacity

// Composite drought score (0-100)
let droughtScore = 0;
droughtScore += Math.min(40, Math.max(0, waterDeficit * 0.8)); // up to 40 pts from deficit
droughtScore += soilDryness * 30; // up to 30 pts from soil dryness
droughtScore += Math.max(0, (temp - 15) * 0.5); // up to ~10 pts from heat
droughtScore += Math.max(0, (60 - humidity) * 0.3); // up to ~18 pts from low humidity
droughtScore = Math.min(100, Math.round(droughtScore));

let severity = 'Low';
let probability = 0.05;
let action = 'monitor';
if (droughtScore >= 75) { severity = 'Critical'; probability = 0.90; action = 'issue_critical_alert'; }
else if (droughtScore >= 55) { severity = 'High'; probability = 0.65; action = 'issue_warning'; }
else if (droughtScore >= 30) { severity = 'Medium'; probability = 0.40; action = 'issue_advisory'; }

return [{ json: {
  incidentType: 'drought',
  severity,
  probability,
  droughtScore,
  total30dPrecipMm: Math.round(total30d * 10) / 10,
  totalET0Mm: Math.round(totalET0 * 10) / 10,
  waterDeficitMm: Math.round(waterDeficit * 10) / 10,
  soilMoisture: Math.round(soilMoisture * 100) / 100,
  temp,
  humidity,
  action,
  shouldAlert: severity !== 'Low',
  timestamp: new Date().toISOString()
}}];
